// ─────────────────────────────────────────────────────────────────
// DEDUPLICATE — By DOI (primary) then by normalized title (fallback)
// ─────────────────────────────────────────────────────────────────
const items = $input.all();
const seenDOI = new Set();
const seenTitle = new Set();
let dupCount = 0;

function normalizeTitle(t) {
  return (t || '').toLowerCase().replace(/[^a-z0-9]/g, '').substring(0, 60);
}

const deduped = items.filter(item => {
  const doi = (item.json.doi || '').toLowerCase().trim();
  const titleKey = normalizeTitle(item.json.title);

  if (doi) {
    if (seenDOI.has(doi)) { dupCount++; return false; }
    seenDOI.add(doi);
  } else {
    if (seenTitle.has(titleKey)) { dupCount++; return false; }
    seenTitle.add(titleKey);
  }
  return true;
});

console.log('Deduplication: ' + items.length + ' -> ' + deduped.length + ' (' + dupCount + ' duplicates removed)');

return deduped.map(item => ({
  json: {
    ...item.json,
    _deduplication_key: item.json.doi || normalizeTitle(item.json.title),
    _total_before_dedup: items.length,
    _duplicates_removed: dupCount
  }
}));
